import React from "react";

const SVGS = [
  "/air_to_water_heat_pump.svg",
  "/air_to_air_heat_pump_correct.svg",
  "/water_to_water_heat_pump.svg",
  "/ground_source_heat_pump.svg",
];

const SLOTS = [
  [3, 6], [12, 4], [22, 10], [31, 3], [42, 8], [53, 5], [64, 12], [75, 4], [86, 9], [94, 6],
  [5, 22], [15, 28], [26, 20], [37, 32], [48, 24], [59, 30], [70, 18], [81, 26], [92, 34], [8, 40],
  [18, 45], [29, 38], [40, 52], [51, 44], [62, 50], [73, 42], [84, 48], [95, 55], [12, 58], [24, 62],
  [35, 68], [46, 60], [57, 72], [68, 64], [79, 70], [90, 58], [6, 75], [20, 82], [33, 78], [45, 85],
  [56, 76], [67, 88], [78, 80], [88, 72], [14, 14], [50, 16], [72, 36], [38, 46], [60, 56], [28, 66],
];

const MACHINES = SLOTS.map(([left, top], i) => ({
  src: SVGS[i % SVGS.length],
  left: `${left}%`,
  top: `${top}%`,
  size: 52 + (i % 5) * 14,
  duration: 9 + (i % 7),
  delay: (i % 11) * 0.6,
}));

export default function BackgroundMachines() {
  return (
    <div className="bg-machines" aria-hidden="true">
      {MACHINES.map((m, i) => (
        <img
          key={i}
          className="bg-machine"
          src={m.src}
          alt=""
          style={{
            left: m.left,
            top: m.top,
            width: m.size,
            height: m.size,
            animationDuration: `${m.duration}s`,
            animationDelay: `${m.delay}s`,
          }}
        />
      ))}
    </div>
  );
}
